// 테스트 모듈 로드
const { game, winningConditions, checkWin, checkDraw, resetGame } = require('./game.js');

// 테스트 결과 추적
let passedTests = 0;
let failedTests = 0;

// 간단한 assertion 함수
function assert(condition, testName) {
    if (condition) {
        console.log(`✓ PASS: ${testName}`);
        passedTests++;
    } else {
        console.log(`✗ FAIL: ${testName}`);
        failedTests++;
    }
}

// 테스트 그룹 출력
function describeTest(groupName) {
    console.log(`\n${groupName}`);
    console.log('─'.repeat(50));
}

// 게임 상태 초기화 헬퍼
function setupGame(boardState, currentPlayer = 'X') {
    resetGame();
    game.board = boardState;
    game.currentPlayer = currentPlayer;
}

// ======== 테스트 시작 ========
console.log('\n🎮 틱택토 게임 테스트 스위트');
console.log('═'.repeat(50));

// 행(Row) 우승 감지 테스트
describeTest('행(Row) 우승 감지 테스트');

setupGame(['X', 'X', 'X', '', 'O', '', '', 'O', '']);
assert(checkWin() === true, '첫 번째 행에서 X 우승');
assert(game.winningCells.join(',') === '0,1,2', '우승 셀 [0,1,2] 확인');

setupGame(['', '', '', 'O', 'O', 'O', 'X', 'X', '']);
assert(checkWin() === true, '두 번째 행에서 O 우승');
assert(game.winningCells.join(',') === '3,4,5', '우승 셀 [3,4,5] 확인');

setupGame(['X', '', 'O', 'O', 'X', '', 'X', 'X', 'X']);
assert(checkWin() === true, '세 번째 행에서 X 우승');
assert(game.winningCells.join(',') === '6,7,8', '우승 셀 [6,7,8] 확인');

// 열(Column) 우승 감지 테스트
describeTest('열(Column) 우승 감지 테스트');

setupGame(['X', 'O', '', 'X', 'O', '', 'X', 'O', '']);
assert(checkWin() === true, '첫 번째 열에서 X 우승');
assert(game.winningCells.join(',') === '0,3,6', '우승 셀 [0,3,6] 확인');

setupGame(['X', 'O', '', 'O', 'O', '', '', 'O', 'X']);
assert(checkWin() === true, '두 번째 열에서 O 우승');
assert(game.winningCells.join(',') === '1,4,7', '우승 셀 [1,4,7] 확인');

setupGame(['', '', 'X', '', '', 'X', 'O', 'O', 'X']);
assert(checkWin() === true, '세 번째 열에서 X 우승');
assert(game.winningCells.join(',') === '2,5,8', '우승 셀 [2,5,8] 확인');

// 대각선(Diagonal) 우승 감지 테스트
describeTest('대각선(Diagonal) 우승 감지 테스트');

setupGame(['X', 'O', '', 'O', 'X', '', '', 'O', 'X']);
assert(checkWin() === true, '좌상단에서 우하단 대각선에서 X 우승');
assert(game.winningCells.join(',') === '0,4,8', '우승 셀 [0,4,8] 확인');

setupGame(['', '', 'O', '', 'O', '', 'O', '', '']);
assert(checkWin() === true, '우상단에서 좌하단 대각선에서 O 우승');
assert(game.winningCells.join(',') === '2,4,6', '우승 셀 [2,4,6] 확인');

// 무승부(Draw) 감지 테스트
describeTest('무승부(Draw) 감지 테스트');

setupGame(['X', 'O', 'X', 'O', 'X', 'O', 'O', 'X', 'O']);
assert(checkDraw() === true, '보드가 가득 찬 경우 무승부');
assert(checkWin() === false, '무승부 상황에서 우승 없음');

setupGame(['', '', '', '', '', '', '', '', '']);
assert(checkDraw() === false, '빈 보드는 무승부 아님');

