// 우승 조건 정의 (인덱스 배열)
const winningConditions = [
    // 행 (rows)
    [0, 1, 2],
    [3, 4, 5],
    [6, 7, 8],
    // 열 (columns)
    [0, 3, 6],
    [1, 4, 7],
    [2, 5, 8],
    // 대각선 (diagonals)
    [0, 4, 8],
    [2, 4, 6]
];

// 게임 상태 관리
const game = {
    board: ['', '', '', '', '', '', '', '', ''],
    currentPlayer: 'X',
    gameOver: false,
    winningCells: []
};

// DOM 요소 선택 (브라우저 환경에서만)
let cells = null;
let currentPlayerDisplay = null;
let winnerDisplay = null;
let resetBtn = null;
let boardElement = null;

if (typeof document !== 'undefined') {
    cells = document.querySelectorAll('.cell');
    currentPlayerDisplay = document.getElementById('current-player');
    winnerDisplay = document.getElementById('winner-display');
    resetBtn = document.getElementById('reset-btn');
    boardElement = document.getElementById('board');

    // 셀 클릭 이벤트 리스너 추가
    cells.forEach(cell => {
        cell.addEventListener('click', handleCellClick);
    });

    // 리셋 버튼 클릭 이벤트
    resetBtn.addEventListener('click', resetGame);
}

// 셀 클릭 핸들러
function handleCellClick(event) {
    const cell = event.target;
    const index = parseInt(cell.dataset.index);

    // 게임이 끝났거나 셀이 이미 점유된 경우 무시
    if (game.gameOver || game.board[index] !== '') {
        return;
    }

    // 보드에 현재 플레이어 마크 추가
    game.board[index] = game.currentPlayer;

    // 셀에 마크 표시 및 스타일 적용
    cell.textContent = game.currentPlayer;
    cell.classList.add(game.currentPlayer.toLowerCase());
    cell.disabled = true;

    // 우승 여부 확인
    if (checkWin()) {
        endGame(`${game.currentPlayer} 우승!`);
        return;
    }

    // 무승부 여부 확인
    if (checkDraw()) {
        endGame('무승부!');
        return;
    }

    // 다음 플레이어로 턴 변경
    game.currentPlayer = game.currentPlayer === 'X' ? 'O' : 'X';
    currentPlayerDisplay.textContent = game.currentPlayer;
}

// 우승 판정 함수
function checkWin() {
    for (let condition of winningConditions) {
        const [a, b, c] = condition;

        // 세 셀이 모두 같은 마크를 가지고 있고, 비어있지 않으면 우승
        if (
            game.board[a] !== '' &&
            game.board[a] === game.board[b] &&
            game.board[b] === game.board[c]
        ) {
            // 우승 셀 저장
            game.winningCells = condition;
            return true;
        }
    }
    return false;
}

// 무승부 판정 함수
function checkDraw() {
    return game.board.every(cell => cell !== '');
}

// 게임 종료 처리
function endGame(message) {
    game.gameOver = true;
    winnerDisplay.textContent = message;

    // 우승 셀 하이라이트
    if (game.winningCells.length > 0) {
        game.winningCells.forEach(index => {
            cells[index].classList.add('winning');
        });
    }

    // 모든 셀 비활성화
    cells.forEach(cell => {
        cell.disabled = true;
    });
}

// 게임 리셋 함수
function resetGame() {
    // 게임 상태 초기화
    game.board = ['', '', '', '', '', '', '', '', ''];
    game.currentPlayer = 'X';
    game.gameOver = false;
    game.winningCells = [];

    // UI 업데이트 (브라우저 환경에서만)
    if (typeof document !== 'undefined') {
        currentPlayerDisplay.textContent = 'X';
        winnerDisplay.textContent = '';

        // 모든 셀 초기화
        cells.forEach(cell => {
            cell.textContent = '';
            cell.classList.remove('x', 'o', 'winning');
            cell.disabled = false;
        });
    }
}

// Node.js 테스트 환경을 위한 export
if (typeof module !== 'undefined' && module.exports) {
    module.exports = {
        game,
        winningConditions,
        checkWin,
        checkDraw,
        resetGame
    };
}

