file.content:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
}

.container {
    background: white;
    padding: 40px;
    border-radius: 15px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
    text-align: center;
}

h1 {
    color: #333;
    margin-bottom: 30px;
    font-size: 2.5em;
    letter-spacing: 2px;
}

.game-info {
    margin-bottom: 30px;
    min-height: 60px;
}

.turn-indicator {
    font-size: 1.2em;
    color: #667eea;
    font-weight: bold;
    margin-bottom: 15px;
}

#current-player {
    color: #764ba2;
    font-size: 1.4em;
}

.winner-display {
    font-size: 1.5em;
    color: #27ae60;
    font-weight: bold;
    min-height: 30px;
}

/* 게임 보드 스타일 */
.board {
    display: grid;
    grid-template-columns: repeat(3, 100px);
    grid-gap: 10px;
    margin: 30px auto;
    background: #f5f5f5;
    padding: 15px;
    border-radius: 10px;
    width: fit-content;
}

.cell {
    width: 100px;
    height: 100px;
    font-size: 2.5em;
    font-weight: bold;
    border: 2px solid #ddd;
    border-radius: 8px;
    background: white;
    cursor: pointer;
    transition: all 0.3s ease;
    color: #333;
}

.cell:hover:not(:disabled) {
    background: #f9f9f9;
    border-color: #667eea;
    transform: scale(1.05);
    box-shadow: 0 5px 15px rgba(102, 126, 234, 0.2);
}

/* 플레이된 셀 */
.cell:disabled {
    cursor: not-allowed;
}

.cell.x {
    color: #667eea;
}

.cell.o {
    color: #764ba2;
}

/* 우승 셀 하이라이트 */
.cell.winning {
    background: #fff9c4;
    border-color: #fbc02d;
    box-shadow: inset 0 0 10px rgba(251, 192, 45, 0.3);
}

/* 리셋 버튼 */
.reset-btn {
    padding: 12px 40px;
    font-size: 1.1em;
    font-weight: bold;
    color: white;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    border: none;
    border-radius: 8px;
    cursor: pointer;
    transition: all 0.3s ease;
    box-shadow: 0 5px 15px rgba(102, 126, 234, 0.3);
}

.reset-btn:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 20px rgba(102, 126, 234, 0.4);
}

.reset-btn:active {
    transform: translateY(0);
}

/* 반응형 디자인 */
@media (max-width: 480px) {
    .container {
        padding: 20px;
    }

    h1 {
        font-size: 2em;
    }

    .board {
        grid-template-columns: repeat(3, 80px);
        gap: 8px;
        padding: 12px;
    }

    .cell {
        width: 80px;
        height: 80px;
        font-size: 2em;
    }
}
